def protect_code(text: str) -> tuple[str, list[str]]:
    protected: list[str] = []

    def keep(match: re.Match[str]) -> str:
        protected.append(match.group(0))
        return f"§§PROTECTED{len(protected) - 1}§§"

    text = re.sub(r"```[\s\S]*?```", keep, text)
    text = re.sub(r"`[^`\n]+`", keep, text)
    text = re.sub(r"\]\([^)]+\)", keep, text)
    text = re.sub(r"<[^>\n]+>", keep, text)
    return text, protected


def restore_code(text: str, protected: list[str]) -> str:
    for index, value in enumerate(protected):
        text = text.replace(f"§§PROTECTED{index}§§", value)
    return text


def polish(text: str) -> str:
    text, protected = protect_code(text)
    for src, dst in sorted(PHRASES.items(), key=lambda item: len(item[0]), reverse=True):
        text = text.replace(src, dst)
    for src, dst in sorted(TERMS.items(), key=lambda item: len(item[0]), reverse=True):
        text = re.sub(rf"\b{re.escape(src)}\b", dst, text)
    for pattern, repl in REGEX_REPLACEMENTS:
        text = re.sub(pattern, repl, text)
    text = text.replace("per per", "per")
    text = text.replace("i i", "i")
    text = text.replace("l’l’", "l’")
    return restore_code(text, protected)


def main() -> None:
    for path in FILES:
        if not path.exists():
            continue
        original = path.read_text(encoding="utf-8")
        updated = polish(original)
        path.write_text(updated, encoding="utf-8")
        print(path)


if __name__ == "__main__":
    main()
